@app.route('/api/stored_script', methods=['POST'])
def create_stored_script():
    """
    Create a stored script from predefined templates only.
    Admin-only endpoint that stores a predefined template as a named stored script.
    """
    try:
        data = request.get_json()
        if not data:
            return jsonify({"error": "Request body must be valid JSON"}), 400

        script_id = data.get('script_id')
        template_name = data.get('template_name')

        if not script_id or not isinstance(script_id, str):
            return jsonify({"error": "Must specify a valid 'script_id'"}), 400

        # Validate script_id format
        if not re.match(r'^[a-zA-Z0-9_\-]+$', script_id) or len(script_id) > 100:
            return jsonify({"error": "Invalid script_id format"}), 400

        if template_name not in ALLOWED_SCRIPT_TEMPLATES:
            return jsonify({
                "error": f"Unknown template: '{template_name}'",
                "available_templates": list(ALLOWED_SCRIPT_TEMPLATES.keys())
            }), 400

        template = ALLOWED_SCRIPT_TEMPLATES[template_name]

        # Store the predefined script
        es.put_script(
            id=script_id,
            body={
                "script": {
                    "lang": "painless",
                    "source": template["source"]
                }
            }
        )

        return jsonify({
            "status": "success",
            "message": f"Stored script '{script_id}' created from template '{template_name}'"
        })

    except Exception as e:
        app.logger.error(f"Error creating stored script: {str(e)}")
        return jsonify({"error": "An error occurred creating the stored script"}), 500


